effect.shader:
float random (vec2 st) {
    return fract(sin(dot(st.xy,
                         vec2(12.9898,78.233)))*
        43758.5453123);
}

// Based on Morgan McGuire @morgan3d
// https://www.shadertoy.com/view/4dS3Wd
float noise (vec2 st) {
    vec2 i = floor(st);
    vec2 f = fract(st);

    // Four corners in 2D of a tile
    float a = random(i);
    float b = random(i + vec2(1.0, 0.0));
    float c = random(i + vec2(0.0, 1.0));
    float d = random(i + vec2(1.0, 1.0));

    vec2 u = f * f * (3.0 - 2.0 * f);

    return mix(a, b, u.x) +
            (c - a)* u.y * (1.0 - u.x) +
            (d - b) * u.x * u.y;
}

float fbm (vec2 st, vec2 parallax, int octaveCount, float intens) {
    // Initial values
    float value = 0.;
    float amplitude = 0.5;
    float frequency = 0.;
    //
    // Loop of octaves
    for (int i = 0; i < octaveCount; i++) {
        value += amplitude * noise(st);
        st *= 2.0;
        st += parallax;
        amplitude *= intens;
    }
    return value;
}


void main() {

    vec2 st;
    if( screenSpace ) {
        st = acScreenNorm;
        st.x *= acScreenSize.x/acScreenSize.y;
    } else {
        st = acLayerNorm;
        st.x *= acLayerSize.x/acLayerSize.y;
    }

    st += offs/1000. * vec2(-1.,1.);

    vec2 parallax = parr/200. * vec2(-1.,1.);

    float dx = fbm( (st-vec2(0.5,0.5))*3.0*scale+vec2(0.5,0.5), parallax, int(octaves), intensity);
    float dy = fbm( ((st+vec2(25.3,12.9))-vec2(0.5,0.5))*3.0*scale+vec2(0.5,0.5), parallax, int(octaves), intensity);

    vec2 sample;
    if( screenSpace ) {
        sample = acScreenNorm;
    } else {
        sample = acLayerNorm;
    }
    sample = sample + vec2(dx-0.5,dy-0.5) * mag;

    if( !screenSpace ) {
        sample = (vec4(sample,0.0,1.0) * acLayerToScreen).xy;
    }

    gl_FragColor = texture2DCv(inputImg.texture,sample);
}
